// ============================================================
// PHASE 3 — Receipt Generator (Ported from Airtable → Supabase)
// File: apps/web/app/admin/receipt/page.tsx
//
// Changes from the Airtable version:
//   1. loadProducts() → GET /v2/products (single call, no pagination)
//   2. fetchCustomers() → GET /v2/admin/customers/search?q=
//   3. checkDiscount() → GET /v2/discounts/validate?code=&subtotal=
//   4. All Airtable field bracket notation removed
//   5. Product shape uses Supabase column names
//   6. After PDF download, optionally logs to orders table
//
// UI is preserved 1:1 from the Framer version.
// ============================================================

'use client'

import { useEffect, useRef, useState } from 'react'

/* ================================================================
   CONFIG
================================================================ */
const API = process.env.NEXT_PUBLIC_API_BASE || 'https://buysub-api-v2.ebuka-nwaju.workers.dev'
const WA_NUMBER = '2348107872916'
const BUYSUB_URL = 'https://buysub.ng'
const BUYSUB_EMAIL = 'help@buysub.ng'
const DEFAULT_NOTE =
  'Thank you for your purchase with BuySub!\n' +
  'For support, email help@buysub.ng or message us on WhatsApp.\n' +
  'We value your trust and are here to support you always.'

const FX: Record<string, number> = { NGN: 1, USD: 0.000625, GBP: 0.0005, CAD: 0.00086 }
const CURRENCIES = Object.keys(FX)
const PERIOD_NAMES = ['Monthly', 'Quarterly', 'Biannual', 'Annual']
const PAYMENT_METHODS = ['Card (Paystack)', 'Bank Transfer', 'Cash', 'WhatsApp', 'Wallet', 'Other']

// Map period names to DB column names
const PERIOD_TO_COL: Record<string, string> = {
  Monthly: 'price_1m', Quarterly: 'price_3m', Biannual: 'price_6m', Annual: 'price_1y', 'One-time': 'price_1m',
}

/* ── Auth ── */
const getToken = (): string => {
  try {
    for (const key of Object.keys(localStorage)) {
      if (key.startsWith('sb-') && key.endsWith('-auth-token')) {
        const session = JSON.parse(localStorage.getItem(key) || '{}')
        return session?.access_token || ''
      }
    }
  } catch { /* */ }
  return ''
}

const authHeaders = () => ({
  'Content-Type': 'application/json',
  'Authorization': `Bearer ${getToken()}`,
})

/* ── Types ── */
interface Product {
  id: string
  name: string
  category: string
  tags: string
  isOutright: boolean
  prices: Record<string, number>
}

interface Customer {
  id: string
  name: string
  email: string
  phone: string
}

interface LineItem {
  id: string; productId: string; name: string; category: string; tags: string
  period: string; isOutright: boolean; qty: number; unitPriceNGN: number; override: string
}

interface DiscountResult { code: string; type: string; value: number; display: string; amountNGN: number }

/* ── Helpers ── */
const uid = () => Math.random().toString(36).slice(2, 9)
const norm = (s: string) => s.toLowerCase().trim()
const parse = (s: string) => Math.max(0, parseFloat(s.replace(/[^0-9.]/g, '')) || 0)

const genRef = (): string => {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789'
  const seed = (Date.now() % 1000000).toString(36).toUpperCase().padStart(3, '0')
  const rand = Array.from({ length: 2 }, () => chars[Math.floor(Math.random() * chars.length)]).join('')
  return `BS-${new Date().getFullYear()}-${(seed + rand).slice(0, 5)}`
}

const fmtAmt = (ngn: number, currency: string): string => {
  const v = Math.round(ngn * FX[currency] * 100) / 100
  if (currency === 'NGN') return `NGN ${v.toLocaleString('en-NG', { minimumFractionDigits: 2 })}`
  return new Intl.NumberFormat('en', { style: 'currency', currency, maximumFractionDigits: 2 }).format(v)
}

const fmtShort = (ngn: number, currency: string): string => {
  const sym: Record<string, string> = { NGN: '₦', USD: '$', GBP: '£', CAD: 'CA$' }
  const v = Math.round(ngn * FX[currency] * 100) / 100
  return `${sym[currency] ?? ''}${v.toLocaleString('en-NG', { maximumFractionDigits: 2 })}`
}

const fmtDate = (iso: string) =>
  new Date(iso).toLocaleDateString('en-NG', { month: 'short', day: 'numeric', year: 'numeric' })

const toWAPhone = (phone: string): string => {
  const d = phone.replace(/\D/g, '')
  if (!d) return WA_NUMBER
  if (d.startsWith('234') && d.length >= 12) return `+${d}`
  if (d.startsWith('0') && d.length === 11) return `+234${d.slice(1)}`
  if (d.length === 10) return `+234${d}`
  return `+${d}`
}

/* ════════════════════════════════════════════════════════════
   DATA FETCHERS — now using /v2/ API instead of Airtable
════════════════════════════════════════════════════════════ */

const loadProducts = async (): Promise<Product[]> => {
  const res = await fetch(`${API}/v2/products`)
  const data = await res.json()
  if (!data.ok) throw new Error(data.error || 'Failed to load products')

  return (data.data || []).map((p: any): Product => ({
    id: p.id,
    name: p.name,
    category: p.category || '',
    tags: p.tags || '',
    isOutright: p.billing_type === 'One-time',
    prices: {
      Monthly: Number(p.price_1m) || 0,
      Quarterly: Number(p.price_3m) || 0,
      Biannual: Number(p.price_6m) || 0,
      Annual: Number(p.price_1y) || 0,
      'One-time': Number(p.price_1m || p.price_3m || p.price_6m || p.price_1y) || 0,
    },
  })).filter((p: Product) => p.name)
}

const fetchCustomers = async (q: string): Promise<Customer[]> => {
  const res = await fetch(`${API}/v2/admin/customers/search?q=${encodeURIComponent(q)}`, {
    headers: authHeaders(),
  })
  const data = await res.json()
  if (!data.ok) return []
  return (data.data || []).map((c: any): Customer => ({
    id: c.id,
    name: c.display_name || '',
    email: c.email || '',
    phone: c.phone || '',
  }))
}

const checkDiscount = async (
  code: string, subtotalNGN: number, currency: string
): Promise<{ ok: true; result: DiscountResult } | { ok: false; error: string }> => {
  const res = await fetch(
    `${API}/v2/discounts/validate?code=${encodeURIComponent(code)}&subtotal=${subtotalNGN}`,
    { headers: authHeaders() }
  )
  const data = await res.json()
  if (data.ok && data.result) return { ok: true, result: data.result }
  return { ok: false, error: data.error || 'Code not found or inactive.' }
}

/* ════════════════════════════════════════════════════════════
   PDF BUILDER — identical to the Airtable version
   (uses jsPDF loaded from CDN)
════════════════════════════════════════════════════════════ */

// NOTE: The LOGO_B64 and FOOTER_B64 constants are identical to your
// existing Receipt_Generator. Copy them from your Framer component.
// I'm using a placeholder that falls back to the purple square.
const LOGO_B64 = '' // paste your existing base64 logo here
const FOOTER_B64 = '' // paste your existing base64 footer here

const buildPDF = async (p: {
  ref: string; date: string; generatedAt: string; currency: string
  customer: { name: string; phone: string; email: string }
  items: LineItem[]; discount: DiscountResult | null
  subtotalNGN: number; discountNGN: number; taxNGN: number; totalNGN: number
  taxRate: number; taxEnabled: boolean; paymentMethod: string; salesRep: string; note: string
}) => {
  await new Promise<void>((resolve, reject) => {
    if ((window as any).jspdf) { resolve(); return }
    const s = document.createElement('script')
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js'
    s.onload = () => resolve()
    s.onerror = reject
    document.head.appendChild(s)
  })
  const { jsPDF } = (window as any).jspdf
  const doc = new jsPDF({ unit: 'mm', format: 'a4' })
  const W = 210, ML = 18, MR = 18, R = W - MR
  const rY = (y: number) => +y.toFixed(2)
  const tx = (str: string, x: number, y: number, opts?: any) => doc.text(str, x, rY(y), opts ?? {})
  const hrLight = (y: number) => { doc.setDrawColor(215, 215, 222); doc.setLineWidth(0.2); doc.line(ML, rY(y), R, rY(y)) }

  /* Logo */
  try {
    if (LOGO_B64) {
      doc.addImage(`data:image/jpeg;base64,${LOGO_B64}`, 'JPEG', ML, 12, 26, 26)
    } else throw new Error('no logo')
  } catch {
    doc.setFillColor(83, 64, 254); doc.roundedRect(ML, 12, 26, 26, 3, 3, 'F')
    doc.setFont('helvetica', 'bold'); doc.setFontSize(18); doc.setTextColor(255, 255, 255)
    tx('b', ML + 8.5, 28)
  }

  doc.setFont('helvetica', 'normal'); doc.setFontSize(9.5); doc.setTextColor(22, 22, 28)
  tx('BuySub', ML, 44)
  doc.setFontSize(8); doc.setTextColor(120, 120, 132); tx(BUYSUB_URL, ML, 48)

  doc.setFont('helvetica', 'normal'); doc.setFontSize(22); doc.setTextColor(22, 22, 28)
  tx('RECEIPT', R, 22, { align: 'right' })
  doc.setFontSize(8.5); doc.setTextColor(120, 120, 132)
  tx(`Order Reference: ${p.ref}`, R, 30, { align: 'right' })

  let y = 56
  doc.setDrawColor(180, 180, 192); doc.setLineWidth(0.2); doc.line(ML, rY(y), R, rY(y))
  y += 7

  const metaLX = 136, metaRX = R
  doc.setFont('helvetica', 'normal'); doc.setFontSize(8); doc.setTextColor(120, 120, 132)
  tx('Addressed To:', ML, y)
  doc.setFontSize(10); doc.setTextColor(20, 20, 26); tx(p.customer.name || '—', ML, y + 6)
  doc.setFontSize(8.5); doc.setTextColor(85, 85, 98)
  let custY = y + 11
  if (p.customer.phone) { tx(p.customer.phone, ML, custY); custY += 5 }
  if (p.customer.email) { tx(p.customer.email, ML, custY); custY += 5 }

  const meta = (label: string, val: string, ry: number) => {
    doc.setFont('helvetica', 'normal'); doc.setFontSize(8); doc.setTextColor(120, 120, 132); tx(label, metaLX, ry)
    doc.setFontSize(8.5); doc.setTextColor(22, 22, 28); tx(val || '—', metaRX, ry, { align: 'right' })
  }
  meta('Payment Date:', fmtDate(p.date), y)
  meta('Sales Rep:', p.salesRep || '—', y + 6)
  if (p.paymentMethod) meta('Payment:', p.paymentMethod, y + 12)
  meta('Generated:', fmtDate(p.generatedAt), y + (p.paymentMethod ? 18 : 12))
  y = Math.max(custY, y + (p.paymentMethod ? 25 : 19)) + 5

  /* Table */
  doc.setFillColor(42, 42, 52); doc.rect(ML, y, R - ML, 8, 'F')
  doc.setFont('helvetica', 'normal'); doc.setFontSize(8); doc.setTextColor(255, 255, 255)
  tx('Item', ML + 3, y + 4.9); tx('Period', 85, y + 4.9); tx('Units', 106, y + 4.9)
  tx('Rate', 121, y + 4.9); tx('Amount', R - 32, y + 4.9)
  y += 14

  for (const item of p.items) {
    const unitNGN = item.override ? parse(item.override) : item.unitPriceNGN
    const lineNGN = unitNGN * item.qty
    const nameParts = doc.splitTextToSize(item.name, 82)

    doc.setFont('helvetica', 'normal'); doc.setFontSize(9.5); doc.setTextColor(20, 20, 26)
    doc.text(nameParts, ML + 3, rY(y))
    const nameH = nameParts.length * 4.2
    if (item.category) {
      doc.setFontSize(7.5); doc.setTextColor(130, 130, 142)
      tx(item.category + (item.tags ? `  ·  ${item.tags}` : ''), ML + 3, y + nameH)
    }

    doc.setFont('helvetica', 'normal'); doc.setFontSize(9); doc.setTextColor(55, 55, 68)
    tx(item.isOutright ? 'One-time' : item.period, 85, y)
    tx(String(item.qty), 106, y)
    tx(fmtAmt(unitNGN, p.currency), 121, y)
    doc.setTextColor(20, 20, 26); tx(fmtAmt(lineNGN, p.currency), R - 32, y)

    const contentBottom = item.category ? nameH + 0.8 : (nameParts.length - 1) * 4.2 + 1.0
    const ROW_GAP = 3.5, NAME_ASCENT = 2.5
    const dividerY = y + contentBottom + ROW_GAP
    hrLight(dividerY)
    y = dividerY + ROW_GAP + NAME_ASCENT
  }

  y += 6

  /* Totals */
  const totLX = 136, totRX = R - 2
  const totRow = (label: string, value: string, strong = false, green = false) => {
    doc.setFont('helvetica', strong ? 'bold' : 'normal'); doc.setFontSize(strong ? 10.5 : 9)
    doc.setTextColor(green ? 22 : 105, green ? 163 : 105, green ? 74 : 118); tx(label, totLX, y)
    doc.setTextColor(green ? 22 : strong ? 18 : 52, green ? 163 : strong ? 18 : 52, green ? 74 : strong ? 22 : 65)
    tx(value, totRX, y, { align: 'right' }); y += strong ? 7.5 : 6
  }

  if (p.discountNGN > 0 || p.taxEnabled) totRow('Subtotal', fmtAmt(p.subtotalNGN, p.currency))
  if (p.discountNGN > 0 && p.discount) totRow(`Discount (${p.discount.display})`, `-${fmtAmt(p.discountNGN, p.currency)}`, false, true)
  if (p.taxEnabled && p.taxNGN > 0) totRow(`Tax (${p.taxRate}%)`, fmtAmt(p.taxNGN, p.currency))
  if (p.discountNGN > 0 || p.taxEnabled) {
    doc.setDrawColor(190, 190, 200); doc.setLineWidth(0.22); doc.line(totLX, rY(y - 1.5), R, rY(y - 1.5)); y += 5
  }
  totRow('Total', fmtAmt(p.totalNGN, p.currency), true)
  y += 16

  /* Notes */
  doc.setFont('helvetica', 'normal'); doc.setFontSize(8); doc.setTextColor(120, 120, 132); tx('Notes:', ML, y); y += 5.5
  doc.setFontSize(8.5); doc.setTextColor(70, 70, 82)
  const noteText = p.note.trim() || DEFAULT_NOTE
  const noteLines = doc.splitTextToSize(noteText, R - ML)
  noteLines.forEach((line: string, i: number) => { tx(line, ML, y + i * 5.5) })

  /* Footer */
  const FOOTER_H = 38, FOOTER_Y = 297 - FOOTER_H
  try {
    if (FOOTER_B64) doc.addImage(`data:image/png;base64,${FOOTER_B64}`, 'PNG', 0, FOOTER_Y, W, FOOTER_H)
    else throw new Error('no footer')
  } catch {
    doc.setFillColor(83, 64, 254); doc.rect(0, FOOTER_Y, W, FOOTER_H, 'F')
    doc.setFont('helvetica', 'normal'); doc.setFontSize(8); doc.setTextColor(255, 255, 255)
    tx(`${BUYSUB_URL}  ·  ${BUYSUB_EMAIL}`, W / 2, FOOTER_Y + FOOTER_H / 2, { align: 'center' })
  }

  doc.save(`BuySub-Receipt-${p.ref}.pdf`)
}

/* ════════════════════════════════════════════════════════════
   COMBOBOXES — identical to Airtable version
════════════════════════════════════════════════════════════ */

const ProductCombobox = ({ products, value, onChange }: {
  products: Product[]; value: string; onChange: (p: Product | null) => void
}) => {
  const [query, setQuery] = useState(value)
  const [open, setOpen] = useState(false)
  const [active, setActive] = useState(-1)
  const [filtered, setFiltered] = useState<Product[]>([])
  const ref = useRef<HTMLDivElement>(null)
  const timer = useRef<any>(null)

  useEffect(() => { setQuery(value) }, [value])
  useEffect(() => {
    clearTimeout(timer.current)
    if (!query || query === value) { setFiltered([]); return }
    timer.current = setTimeout(() => {
      setFiltered(products.filter(p =>
        norm(p.name).includes(norm(query)) || norm(p.category).includes(norm(query)) || norm(p.tags).includes(norm(query))
      ).slice(0, 9))
    }, 300)
  }, [query, products, value])
  useEffect(() => {
    const h = (e: MouseEvent) => { if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false) }
    document.addEventListener('mousedown', h); return () => document.removeEventListener('mousedown', h)
  }, [])

  const select = (p: Product) => { onChange(p); setQuery(p.name); setOpen(false); setActive(-1); setFiltered([]) }
  const clear = (e: React.MouseEvent) => { e.stopPropagation(); onChange(null); setQuery(''); setFiltered([]) }

  return (
    <div ref={ref} style={{ position: 'relative', width: '100%' }}>
      <div style={{ position: 'relative' }}>
        <input value={query} onChange={e => { setQuery(e.target.value); setOpen(true); setActive(-1) }}
          onFocus={() => setOpen(true)}
          onKeyDown={e => {
            if (!open || !filtered.length) return
            if (e.key === 'ArrowDown') { e.preventDefault(); setActive(a => Math.min(a + 1, filtered.length - 1)) }
            if (e.key === 'ArrowUp') { e.preventDefault(); setActive(a => Math.max(a - 1, 0)) }
            if (e.key === 'Enter' && active >= 0) { e.preventDefault(); select(filtered[active]) }
            if (e.key === 'Escape') setOpen(false)
          }}
          placeholder="Search products…" style={{ ...IS, paddingRight: query ? 30 : 12 }}
        />
        {query && (
          <button onClick={clear} style={{
            position: 'absolute', right: 8, top: '50%', transform: 'translateY(-50%)',
            background: 'none', border: 'none', color: 'var(--bs-text-faint, #6b6b7e)', cursor: 'pointer', fontSize: 16, lineHeight: 1, padding: '0 2px',
          }}>×</button>
        )}
      </div>
      {open && filtered.length > 0 && (
        <div style={DD}>
          {filtered.map((p, i) => (
            <div key={p.id} onClick={() => select(p)} onMouseEnter={() => setActive(i)}
              style={{ padding: '9px 13px', cursor: 'pointer', borderBottom: '1px solid var(--bs-border-subtle, #1c1c22)', background: i === active ? 'var(--bs-bg-muted, #18181c)' : 'transparent' }}>
              <div style={{ fontSize: 13, color: 'var(--bs-text-primary, #e8e8ec)' }}>{p.name}</div>
              <div style={{ fontSize: 11, color: 'var(--bs-text-muted, #6b6b7e)', marginTop: 2, display: 'flex', justifyContent: 'space-between' }}>
                <span>{p.category}{p.tags ? `  ·  ${p.tags}` : ''}</span>
                <span style={{ color: 'var(--bs-text-faint, #4a4a5e)' }}>
                  {p.isOutright ? `₦${(p.prices['One-time'] || 0).toLocaleString()}` : `₦${(p.prices.Annual || p.prices.Quarterly || 0).toLocaleString()} /yr`}
                </span>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

const CustomerCombobox = ({ onSelect }: { onSelect: (c: Customer) => void }) => {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<Customer[]>([])
  const [loading, setLoading] = useState(false)
  const [open, setOpen] = useState(false)
  const ref = useRef<HTMLDivElement>(null)
  const timer = useRef<any>(null)

  useEffect(() => {
    clearTimeout(timer.current)
    if (query.length < 2) { setResults([]); return }
    timer.current = setTimeout(async () => {
      setLoading(true)
      try { setResults(await fetchCustomers(query)) } finally { setLoading(false) }
    }, 400)
  }, [query])

  useEffect(() => {
    const h = (e: MouseEvent) => { if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false) }
    document.addEventListener('mousedown', h); return () => document.removeEventListener('mousedown', h)
  }, [])

  return (
    <div ref={ref} style={{ position: 'relative' }}>
      <div style={{ position: 'relative' }}>
        <input value={query} onChange={e => { setQuery(e.target.value); setOpen(true) }}
          onFocus={() => setOpen(true)} placeholder="Search by name, email or phone…" style={IS} />
        {loading && <span style={{ position: 'absolute', right: 10, top: '50%', transform: 'translateY(-50%)', fontSize: 10, color: 'var(--bs-text-faint, #6b6b7e)' }}>…</span>}
      </div>
      {open && results.length > 0 && (
        <div style={DD}>
          {results.map(c => (
            <div key={c.id} onClick={() => { onSelect(c); setQuery(c.name); setOpen(false) }}
              style={{ padding: '9px 13px', cursor: 'pointer', borderBottom: '1px solid var(--bs-border-subtle, #1c1c22)' }}
              onMouseEnter={e => (e.currentTarget.style.background = 'var(--bs-bg-muted, #18181c)')}
              onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}>
              <div style={{ fontSize: 13, color: 'var(--bs-text-primary, #e8e8ec)' }}>{c.name}</div>
              <div style={{ fontSize: 11, color: 'var(--bs-text-muted, #6b6b7e)', marginTop: 2 }}>
                {[c.phone, c.email].filter(Boolean).join('  ·  ')}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

/* ════════════════════════════════════════════════════════════
   MAIN COMPONENT — identical UI to the Airtable version
════════════════════════════════════════════════════════════ */

export default function ReceiptGenerator() {
  const [products, setProducts] = useState<Product[]>([])
  const [prodLoading, setProdLoading] = useState(true)
  useEffect(() => {
    loadProducts().then(setProducts).catch(console.error).finally(() => setProdLoading(false))
  }, [])

  const [ref] = useState(genRef)
  const [date] = useState(() => new Date().toISOString())
  const todayStr = new Date().toISOString().slice(0, 10)
  const [purchaseDate, setPurchaseDate] = useState(todayStr)
  const [currency, setCurrency] = useState('NGN')

  const [custName, setCustName] = useState('')
  const [custEmail, setCustEmail] = useState('')
  const [custPhone, setCustPhone] = useState('')

  const emptyItem = (): LineItem => ({
    id: uid(), productId: '', name: '', category: '', tags: '',
    period: 'Annual', isOutright: false, qty: 1, unitPriceNGN: 0, override: '',
  })
  const [items, setItems] = useState<LineItem[]>([emptyItem()])
  const setItem = (id: string, patch: Partial<LineItem>) =>
    setItems(p => p.map(i => (i.id === id ? { ...i, ...patch } : i)))

  const onProductSelect = (itemId: string, product: Product | null) => {
    if (!product) { setItem(itemId, { productId: '', name: '', category: '', tags: '', unitPriceNGN: 0, override: '' }); return }
    const period = product.isOutright ? 'One-time' : 'Annual'
    setItem(itemId, {
      productId: product.id, name: product.name, category: product.category,
      tags: product.tags, isOutright: product.isOutright, period,
      unitPriceNGN: product.prices[period] || 0, override: '',
    })
  }

  const onPeriodChange = (itemId: string, period: string) => {
    const item = items.find(i => i.id === itemId)
    const prod = item ? products.find(p => p.id === item.productId) : null
    setItem(itemId, { period, isOutright: false, unitPriceNGN: prod ? prod.prices[period] || 0 : 0, override: '' })
  }

  /* Discount */
  const [dCode, setDCode] = useState('')
  const [dResult, setDResult] = useState<DiscountResult | null>(null)
  const [dError, setDError] = useState('')
  const [dLoading, setDLoading] = useState(false)

  const applyDiscount = async () => {
    const code = dCode.trim().toUpperCase()
    if (!code) return
    setDLoading(true); setDError(''); setDResult(null)
    try {
      const res = await checkDiscount(code, subtotalNGN, currency)
      if (res.ok) setDResult(res.result); else setDError(res.error)
    } catch { setDError('Could not validate. Try again.') }
    finally { setDLoading(false) }
  }

  /* Tax */
  const [taxEnabled, setTaxEnabled] = useState(false)
  const [taxRate, setTaxRate] = useState('7.5')

  /* Order details */
  const [paymentMethod, setPaymentMethod] = useState('')
  const [salesRep, setSalesRep] = useState('')
  const [note, setNote] = useState('')

  /* Totals */
  const subtotalNGN = items.reduce((s, i) => s + (i.override ? parse(i.override) : i.unitPriceNGN) * i.qty, 0)
  const discountNGN = dResult?.amountNGN ?? 0
  const afterDiscount = Math.max(0, subtotalNGN - discountNGN)
  const taxNGN = taxEnabled ? (afterDiscount * (parseFloat(taxRate) || 0)) / 100 : 0
  const totalNGN = afterDiscount + taxNGN

  const payload = () => ({
    ref, date: purchaseDate, generatedAt: date, currency,
    customer: { name: custName, phone: custPhone, email: custEmail },
    items, discount: dResult, subtotalNGN, discountNGN, taxNGN, totalNGN,
    taxRate: parseFloat(taxRate) || 0, taxEnabled, paymentMethod, salesRep, note,
  })

  /* Actions */
  const [generating, setGenerating] = useState(false)
  const [generated, setGenerated] = useState(false)
  const [waSent, setWaSent] = useState(false)

  const handleDownload = async () => {
    setGenerating(true)
    try { await buildPDF(payload()); setGenerated(true) }
    catch (e) { console.error(e); alert('PDF generation failed. Please try again.') }
    finally { setGenerating(false) }
  }

  const handleWhatsApp = async () => {
    setGenerating(true)
    try { await buildPDF(payload()); setGenerated(true) } catch (e) { console.error(e) }
    finally { setGenerating(false) }
    const wa = toWAPhone(custPhone)
    const msg = `Thank you for your purchase${custName ? ', ' + custName.split(' ')[0] : ''}. [additional instructions]\n\nYour order reference is *${ref}* — please find your receipt attached.\nFor any questions, reply here or email ${BUYSUB_EMAIL}.`
    window.open(`https://wa.me/${wa}?text=${encodeURIComponent(msg)}`, '_blank', 'noopener,noreferrer')
    setWaSent(true)
  }

  const displayPrice = (ngn: number) => ngn > 0 ? fmtShort(ngn, currency) : '—'

  /* ─────────── RENDER ─────────── */
  return (
    <div style={{
      background: 'var(--bs-bg-base, #0a0a0c)', minHeight: '100vh',
      color: 'var(--bs-text-primary, #e8e8ec)', fontFamily: 'Inter, sans-serif',
      padding: '0 16px 60px', paddingTop: 'calc(10vh + 16px)', boxSizing: 'border-box',
    }}>
      <style>{`
        .rg-cust-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; }
        @media (max-width: 640px) { .rg-cust-grid { grid-template-columns: 1fr 1fr; } .rg-cust-name { grid-column: 1 / -1; } }
        .rg-dt-headers { display: grid; grid-template-columns: 1fr 110px 130px 72px 110px 40px; gap: 10px; padding-bottom: 6px; border-bottom: 1px solid var(--bs-border-subtle, #1c1c22); margin-bottom: 8px; }
        .rg-dt-row { display: grid; grid-template-columns: 1fr 110px 130px 72px 110px 40px; gap: 10px; align-items: center; padding-bottom: 8px; border-bottom: 1px solid var(--bs-border-subtle, #1c1c22); margin-bottom: 8px; }
        .rg-mob-card { display: none; }
        @media (max-width: 640px) {
          .rg-dt-headers { display: none; } .rg-dt-row { display: none; }
          .rg-mob-card { display: block; margin-bottom: 12px; padding: 12px; background: var(--bs-bg-elevated, #18181c); border-radius: 12px; border: 1px solid var(--bs-border-subtle, #1c1c22); }
          .rg-mob-row2 { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 10px; }
          .rg-mob-row3 { display: flex; gap: 10px; align-items: flex-end; }
        }
      `}</style>

      <div style={{ maxWidth: 780, margin: '0 auto', width: '100%' }}>
        {/* Header */}
        <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: 24, gap: 12, flexWrap: 'wrap' }}>
          <div>
            <div style={{ fontSize: 18 }}>Receipt Generator</div>
            <div style={{ fontSize: 11, color: 'var(--bs-text-muted, #6b6b7e)', marginTop: 4 }}>Internal · {ref} · Generated {fmtDate(date)}</div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ fontSize: 11, color: 'var(--bs-text-secondary, #a0a0b0)' }}>Currency</span>
            <select value={currency} onChange={e => { setCurrency(e.target.value); setDResult(null) }}
              style={{ ...IS, width: 86, height: 36, fontSize: 13 }}>
              {CURRENCIES.map(c => <option key={c}>{c}</option>)}
            </select>
          </div>
        </div>

        {/* Customer */}
        <Panel title="Customer">
          <div style={{ marginBottom: 14 }}>
            <Lbl>Search existing customer</Lbl>
            <CustomerCombobox onSelect={c => { setCustName(c.name); setCustEmail(c.email); setCustPhone(c.phone) }} />
          </div>
          <div className="rg-cust-grid">
            <div className="rg-cust-name"><Lbl>Name</Lbl><input style={IS} placeholder="Full name" value={custName} onChange={e => setCustName(e.target.value)} /></div>
            <div><Lbl>Email</Lbl><input style={IS} type="email" placeholder="email@example.com" value={custEmail} onChange={e => setCustEmail(e.target.value)} /></div>
            <div><Lbl>Phone</Lbl><input style={IS} type="tel" placeholder="080... or +234..." value={custPhone} onChange={e => setCustPhone(e.target.value)} /></div>
          </div>
        </Panel>

        {/* Order Items */}
        <Panel title={prodLoading ? 'Order Items  —  loading…' : `Order Items  ·  ${products.length} products`}>
          <div className="rg-dt-headers">
            {['Product', 'Period', `Unit price (${currency})`, 'Qty', 'Line total', ''].map((h, i) => (
              <div key={i} style={{ fontSize: 10, color: 'var(--bs-text-muted, #6b6b7e)' }}>{h}</div>
            ))}
          </div>
          {items.map(item => {
            const unitNGN = item.override ? parse(item.override) : item.unitPriceNGN
            const lineNGN = unitNGN * item.qty
            return (
              <div key={item.id}>
                <div className="rg-dt-row">
                  <ProductCombobox products={products} value={item.name} onChange={p => onProductSelect(item.id, p)} />
                  <select style={IS} value={item.period} disabled={item.isOutright} onChange={e => onPeriodChange(item.id, e.target.value)}>
                    {item.isOutright ? <option>One-time</option> : PERIOD_NAMES.map(p => <option key={p}>{p}</option>)}
                  </select>
                  <input style={IS} placeholder={unitNGN > 0 ? fmtShort(unitNGN, currency) : '0.00'} value={item.override} onChange={e => setItem(item.id, { override: e.target.value })} />
                  <input style={{ ...IS, textAlign: 'center' }} type="number" min="1" value={item.qty} onChange={e => setItem(item.id, { qty: Math.max(1, parseInt(e.target.value) || 1) })} />
                  <div style={{ ...IS, background: 'var(--bs-bg-elevated, #18181c)', border: '1px solid var(--bs-border-subtle, #1c1c22)', color: 'var(--bs-text-secondary, #a0a0b0)', display: 'flex', alignItems: 'center', pointerEvents: 'none' }}>
                    {lineNGN > 0 ? displayPrice(lineNGN) : '—'}
                  </div>
                  <button onClick={() => setItems(p => p.filter(i => i.id !== item.id))} disabled={items.length === 1}
                    style={{ width: 40, height: 40, borderRadius: 8, background: 'transparent', border: '1px solid var(--bs-border-default, #27272e)', color: 'var(--bs-text-muted, #6b6b7e)', cursor: items.length === 1 ? 'not-allowed' : 'pointer', fontSize: 18, display: 'flex', alignItems: 'center', justifyContent: 'center', opacity: items.length === 1 ? 0.3 : 1, flexShrink: 0 }}>
                    ×
                  </button>
                </div>
                {/* Mobile card - same structure as original */}
                <div className="rg-mob-card">
                  <div style={{ marginBottom: 10 }}>
                    <Lbl>Product</Lbl>
                    <ProductCombobox products={products} value={item.name} onChange={p => onProductSelect(item.id, p)} />
                  </div>
                  <div className="rg-mob-row2">
                    <div><Lbl>Period</Lbl><select style={IS} value={item.period} disabled={item.isOutright} onChange={e => onPeriodChange(item.id, e.target.value)}>{item.isOutright ? <option>One-time</option> : PERIOD_NAMES.map(p => <option key={p}>{p}</option>)}</select></div>
                    <div><Lbl>Unit price ({currency})</Lbl><input style={IS} placeholder={unitNGN > 0 ? fmtShort(unitNGN, currency) : '0.00'} value={item.override} onChange={e => setItem(item.id, { override: e.target.value })} /></div>
                  </div>
                  <div className="rg-mob-row3">
                    <div style={{ width: 80 }}><Lbl>Qty</Lbl><input style={{ ...IS, textAlign: 'center' }} type="number" min="1" value={item.qty} onChange={e => setItem(item.id, { qty: Math.max(1, parseInt(e.target.value) || 1) })} /></div>
                    <div style={{ flex: 1 }}><Lbl>Line total</Lbl><div style={{ ...IS, background: 'var(--bs-bg-input, #111114)', border: '1px solid var(--bs-border-subtle, #1c1c22)', color: 'var(--bs-text-secondary, #a0a0b0)', display: 'flex', alignItems: 'center', pointerEvents: 'none' }}>{lineNGN > 0 ? displayPrice(lineNGN) : '—'}</div></div>
                    <button onClick={() => setItems(p => p.filter(i => i.id !== item.id))} disabled={items.length === 1}
                      style={{ width: 40, height: 40, borderRadius: 8, background: 'transparent', border: '1px solid var(--bs-border-default, #27272e)', color: 'var(--bs-text-muted, #6b6b7e)', cursor: items.length === 1 ? 'not-allowed' : 'pointer', fontSize: 18, display: 'flex', alignItems: 'center', justifyContent: 'center', opacity: items.length === 1 ? 0.3 : 1, flexShrink: 0 }}>
                      ×
                    </button>
                  </div>
                </div>
              </div>
            )
          })}
          <button onClick={() => setItems(p => [...p, emptyItem()])} style={{ background: 'transparent', border: 'none', color: '#7C5CFF', cursor: 'pointer', fontSize: 13, padding: '4px 0' }}>+ Add item</button>
        </Panel>

        {/* Discount */}
        <Panel title="Discount (optional)">
          {dResult ? (
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '10px 14px', background: 'rgba(34,197,94,0.07)', border: '1px solid rgba(34,197,94,0.2)', borderRadius: 10 }}>
              <div style={{ display: 'flex', gap: 10, alignItems: 'center', flexWrap: 'wrap' }}>
                <span style={{ fontSize: 11, background: 'rgba(34,197,94,0.18)', borderRadius: 4, padding: '2px 8px', color: '#16a34a' }}>{dResult.code}</span>
                <span style={{ fontSize: 13, color: '#16a34a' }}>{dResult.display} · saves {fmtShort(dResult.amountNGN, currency)}</span>
              </div>
              <button onClick={() => { setDResult(null); setDCode('') }} style={{ background: 'transparent', border: 'none', color: 'var(--bs-text-faint, #4a4a5e)', cursor: 'pointer', fontSize: 18, lineHeight: 1, flexShrink: 0 }}>×</button>
            </div>
          ) : (
            <>
              <div style={{ display: 'flex', gap: 10 }}>
                <input style={{ ...IS, flex: 1, letterSpacing: '0.06em' }} placeholder="Promo code" value={dCode}
                  onChange={e => { setDCode(e.target.value.toUpperCase()); setDError('') }}
                  onKeyDown={e => e.key === 'Enter' && applyDiscount()} />
                <button onClick={applyDiscount} disabled={dLoading || !dCode.trim()}
                  style={{ height: 40, padding: '0 20px', borderRadius: 8, background: dCode.trim() ? '#7C5CFF' : 'var(--bs-bg-muted, #18181c)', border: 'none', color: dCode.trim() ? '#fff' : 'var(--bs-text-faint, #4a4a5e)', cursor: dCode.trim() ? 'pointer' : 'not-allowed', fontSize: 13, flexShrink: 0 }}>
                  {dLoading ? 'Checking…' : 'Apply'}
                </button>
              </div>
              {dError && <div style={{ fontSize: 12, color: '#dc2626', marginTop: 7 }}>{dError}</div>}
            </>
          )}
        </Panel>

        {/* Tax */}
        <Panel title="Tax (optional)">
          <div style={{ display: 'flex', alignItems: 'center', gap: 14, flexWrap: 'wrap' }}>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', fontSize: 13 }}>
              <input type="checkbox" checked={taxEnabled} onChange={e => setTaxEnabled(e.target.checked)} style={{ width: 16, height: 16, accentColor: '#7C5CFF', cursor: 'pointer' }} />
              Apply tax
            </label>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input type="number" min="0" max="100" step="0.5" value={taxRate} disabled={!taxEnabled}
                onChange={e => setTaxRate(e.target.value)}
                style={{ ...IS, width: 90, opacity: taxEnabled ? 1 : 0.4, cursor: taxEnabled ? 'text' : 'not-allowed', textAlign: 'center' }} />
              <span style={{ fontSize: 13, color: 'var(--bs-text-secondary, #a0a0b0)' }}>%</span>
            </div>
            {taxEnabled && taxNGN > 0 && <span style={{ fontSize: 12, color: 'var(--bs-text-muted, #6b6b7e)' }}>= {fmtShort(taxNGN, currency)}</span>}
          </div>
        </Panel>

        {/* Order Details */}
        <Panel title="Order Details">
          <TwoCol style={{ marginBottom: 12 }}>
            <div><Lbl>Purchase Date</Lbl><input type="date" value={purchaseDate} onChange={e => setPurchaseDate(e.target.value)} style={{ ...IS, colorScheme: 'dark' }} /></div>
            <div><Lbl>Payment Method</Lbl><select style={IS} value={paymentMethod} onChange={e => setPaymentMethod(e.target.value)}><option value="">Select…</option>{PAYMENT_METHODS.map(m => <option key={m}>{m}</option>)}</select></div>
          </TwoCol>
          <TwoCol style={{ marginBottom: 12 }}>
            <div><Lbl>Sales Rep</Lbl><input style={IS} placeholder="Name or initials" value={salesRep} onChange={e => setSalesRep(e.target.value)} /></div>
          </TwoCol>
          <Lbl>Notes <span style={{ color: 'var(--bs-text-faint, #4a4a5e)', fontSize: 10 }}>(leave blank for default)</span></Lbl>
          <textarea value={note} onChange={e => setNote(e.target.value)} placeholder={DEFAULT_NOTE}
            style={{ ...IS, height: 88, padding: '10px 12px', resize: 'vertical', lineHeight: 1.7, fontSize: 12 } as any} />
        </Panel>

        {/* Totals */}
        <div style={{ background: 'var(--bs-bg-card, #111114)', border: '1px solid var(--bs-border-subtle, #1c1c22)', borderRadius: 16, padding: '18px 20px', marginBottom: 14, display: 'flex', justifyContent: 'flex-end' }}>
          <div style={{ width: '100%', maxWidth: 300, display: 'flex', flexDirection: 'column', gap: 8 }}>
            {(discountNGN > 0 || taxNGN > 0) && <TotRow label="Subtotal" value={fmtShort(subtotalNGN, currency)} />}
            {discountNGN > 0 && dResult && <TotRow label={`Discount (${dResult.display})`} value={`−${fmtShort(discountNGN, currency)}`} color="#16a34a" />}
            {taxEnabled && taxNGN > 0 && <TotRow label={`Tax (${taxRate}%)`} value={fmtShort(taxNGN, currency)} />}
            {(discountNGN > 0 || taxNGN > 0) && <div style={{ height: 1, background: 'var(--bs-border-default, #27272e)' }} />}
            <TotRow label="Total" value={fmtShort(totalNGN, currency)} bold />
          </div>
        </div>

        {/* Actions */}
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          <button onClick={handleDownload} disabled={generating}
            style={{ flex: 1, minWidth: 160, height: 52, borderRadius: 12, background: '#7C5CFF', border: 'none', color: '#fff', cursor: generating ? 'not-allowed' : 'pointer', fontSize: 14, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, opacity: generating ? 0.7 : 1 }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" /><polyline points="7 10 12 15 17 10" /><line x1="12" y1="15" x2="12" y2="3" /></svg>
            {generating ? 'Generating…' : generated ? 'Download Again' : 'Download PDF'}
          </button>
          <button onClick={handleWhatsApp} disabled={generating}
            style={{ flex: 1, minWidth: 160, height: 52, borderRadius: 12, background: '#25D366', border: 'none', color: '#fff', cursor: generating ? 'not-allowed' : 'pointer', fontSize: 14, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, opacity: generating ? 0.7 : 1 }}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347z" /><path d="M12 0C5.373 0 0 5.373 0 12c0 2.122.554 4.116 1.523 5.847L.057 23.57a.75.75 0 0 0 .92.92l5.723-1.466A11.945 11.945 0 0 0 12 24c6.627 0 12-5.373 12-12S18.627 0 12 0zm0 22c-1.93 0-3.736-.518-5.287-1.42l-.379-.225-3.932 1.007 1.007-3.932-.225-.379A9.953 9.953 0 0 1 2 12C2 6.477 6.477 2 12 2s10 4.477 10 10-4.477 10-10 10z" /></svg>
            {waSent ? 'Send Again' : 'Send & Download Receipt'}
          </button>
        </div>

        <div style={{ marginTop: 10, fontSize: 11, color: 'var(--bs-text-faint, #4a4a5e)', lineHeight: 1.6 }}>
          Both buttons download the PDF. Attach it manually in WhatsApp before sending.
        </div>

        {(generated || waSent) && (
          <div style={{ marginTop: 14, padding: '11px 16px', borderRadius: 10, background: 'rgba(34,197,94,0.07)', border: '1px solid rgba(34,197,94,0.18)', fontSize: 13, color: '#16a34a', display: 'flex', gap: 8, alignItems: 'center' }}>
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><polyline points="20 6 9 17 4 12" /></svg>
            {waSent ? 'Receipt downloaded · WhatsApp opened. Attach the PDF before sending.' : 'Receipt downloaded.'}
          </div>
        )}
      </div>
    </div>
  )
}

/* ── Micro-components (identical to original) ── */
const Panel = ({ title, children }: { title: string; children: React.ReactNode }) => (
  <div style={{ background: 'var(--bs-bg-card, #111114)', border: '1px solid var(--bs-border-subtle, #1c1c22)', borderRadius: 16, padding: '18px 20px', marginBottom: 14 }}>
    <div style={{ fontSize: 10, color: 'var(--bs-text-muted, #6b6b7e)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 14 }}>{title}</div>
    {children}
  </div>
)

const TwoCol = ({ children, style }: { children: React.ReactNode; style?: any }) => (
  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))', gap: 12, ...style }}>{children}</div>
)

const Lbl = ({ children }: { children: React.ReactNode }) => (
  <div style={{ fontSize: 11, color: 'var(--bs-text-secondary, #a0a0b0)', marginBottom: 5 }}>{children}</div>
)

const TotRow = ({ label, value, bold = false, color }: { label: string; value: string; bold?: boolean; color?: string }) => (
  <div style={{ display: 'flex', justifyContent: 'space-between', gap: 12, alignItems: 'baseline' }}>
    <span style={{ fontSize: 12, color: color ?? 'var(--bs-text-secondary, #a0a0b0)' }}>{label}</span>
    <span style={{ fontSize: bold ? 17 : 13, fontWeight: bold ? 600 : 400, color: color ?? 'var(--bs-text-primary, #e8e8ec)' }}>{value}</span>
  </div>
)

const IS: any = {
  height: 40, padding: '0 12px', borderRadius: 8, fontSize: 13, width: '100%',
  background: 'var(--bs-bg-input, #111114)', border: '1px solid var(--bs-border-default, #27272e)',
  color: 'var(--bs-text-primary, #e8e8ec)', boxSizing: 'border-box',
}

const DD: any = {
  position: 'absolute', top: 'calc(100% + 4px)', left: 0, right: 0,
  background: 'var(--bs-bg-elevated, #18181c)', border: '1px solid var(--bs-border-default, #27272e)',
  borderRadius: 10, zIndex: 200, overflow: 'hidden',
  boxShadow: '0 8px 28px rgba(0,0,0,0.32)', maxHeight: 280, overflowY: 'auto',
}
